CREATE SEQUENCE "draw"."${tableName}__gid_seq" INCREMENT 1 MINVALUE 1 MAXVALUE 9223372036854775807 START 1 CACHE 1;

CREATE TABLE "draw"."${tableName}" (

	_gid int8 DEFAULT nextval( 'draw.${tableName}__gid_seq' :: regclass ),
	_annox NUMERIC ( 20, 4 ),
	_annoy NUMERIC ( 20, 4 ),

	 	"${map.colNm}" ${map.colType}

	,_geometry geometry ( ${layerType}, 5186 ),

	CONSTRAINT "${tableName}_pk" PRIMARY KEY ("_gid")
);

COMMENT ON TABLE "draw"."${tableName}" IS '${tableKoreaName}';

COMMENT ON COLUMN "draw"."${tableName}"."_gid" IS '식별번호';
COMMENT ON COLUMN "draw"."${tableName}"."_annox" IS '주기X좌표';
COMMENT ON COLUMN "draw"."${tableName}"."_annoy" IS '주기Y좌표';

	COMMENT ON COLUMN "draw"."${tableName}"."${map.colNm}" IS '${map.colKrNm}';

COMMENT ON COLUMN "draw"."${tableName}"."_geometry" IS '도형식별번호';


ALTER SEQUENCE "draw"."${tableName}__gid_seq" OWNED BY "draw"."${tableName}"._gid;


CREATE INDEX "draw_${tableName}__gid_idx" ON "draw"."${tableName}" USING btree ( _gid );
CREATE INDEX "draw_${tableName}_geom_idx" ON "draw"."${tableName}" USING gist ( _geometry );
